\begin{poem}
\verse{Soneto}
\verse{}
\verse{Pálida, à luz da lâmpada sombria,}
\verse{Sobre o leito de flores reclinada,}
\verse{Como a lua por noite embalsamada,}
\verse{Entre as nuvens do amor ela dormia!}
\verse{}
\verse{Era a virgem do mar, na escuma fria}
\verse{Pela maré das águas embalada!}
\verse{Era um anjo entre nuvens d'alvorada}
\verse{Que em sonhos se banhava e se esquecia!}
\verse{}
\verse{Era mais bela! o seio palpitando...}
\verse{Negros olhos as pálpebras abrindo...}
\verse{Formas nuas no leito resvalando...}
\verse{}
\verse{Não te rias de mim, meu anjo lindo!}
\verse{Por ti as noites eu velei chorando,}
\verse{Por ti nos sonhos morrerei sorrindo!}
\end{poem}

\credits{AZEVEDO, Álvares de. Disponível em: <http://www.academia.org.br/academicos/alvares-de-azevedo/textos-escolhidos>. Acesso em: 11 ago. 2017.}

\begin{poem}
\verse{Com licença poética}
\verse{}
\verse{Quando nasci um anjo esbelto,}
\verse{desses que tocam trombeta, anunciou:}
\verse{vai carregar bandeira.}
\verse{Cargo muito pesado pra mulher,}
\verse{esta espécie ainda envergonhada.}
\verse{Aceito os subterfúgios que me cabem,}
\verse{sem precisar mentir.}
\verse{Não sou tão feia que não possa casar,}
\verse{acho o Rio de Janeiro uma beleza e}
\verse{ora sim, ora não, creio em parto sem dor.}
\verse{Mas o que sinto escrevo. Cumpro a sina.}
\verse{Inauguro linhagens, fundo reinos}
\verse{(dor não é amargura).}
\verse{Minha tristeza não tem pedigree,}
\verse{já a minha vontade de alegria,}
\verse{sua raiz vai ao meu mil avô.}
\verse{Vai ser coxo na vida, é maldição pra homem.}
\verse{Mulher é desdobrável. Eu sou.}
\end{poem}

\credits{PRADO, Adélia. Bagagem. São Paulo: Siciliano, 1993, p.11.}
